INSERT INTO `cfop` (`id`,`codigocfop`,`descricao`,`aplicacao`,`ativo`) VALUES 
 (1,'1000','ENTRADAS OU AQUISICOES DE SERVICOS DO ESTADO','CLASSIFICAM-SE, NESTE GRUPO, AS OPERACOES OU PRESTACOES EM QUE O ESTABELECIMENTO REMETENTE ESTEJA LOCALIZADO NA MESMA UNIDADE DA FEDERACAO DO DESTINATARIO','1'),
 (2,'1100','COMPRAS PARA INDUSTRIALIZACAO, PRODUCAO RURAL, COMERCIALIZACAO OU PRESTACAO DE SERVICOS','(NR AJUSTE SINIEF 05/2005) (DECRETO NO 28.868, DE 31/01/2006)\r\n\r\n(DEC. 28.868/2006 â EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (3,'1101','COMPRA PARA INDUSTRIALIZACAO OU PRODUCAO RURAL (NR AJUSTE SINIEF 05/2005) (DECRETO 28.868/2006)','COMPRA DE MERCADORIA A SER UTILIZADA EM PROCESSO DE INDUSTRIALIZACAO OU PRODUCAO RURAL, BEM COMO A ENTRADA DE MERCADORIA EM ESTABELECIMENTO INDUSTRIAL OU PRODUTOR RURAL DE COOPERATIVA RECEBIDA DE SEUS COOPERADOS OU DE ESTABELECIMENTO DE OUTRA COOPERATIVA.\r\n(DECRETO NO 28.868, DE 31/01/2006-â EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005).','1'),
 (4,'1102','COMPRA PARA COMERCIALIZACAO','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS DE MERCADORIAS A SEREM COMERCIALIZADAS. TAMBEM SERAO CLASSIFICADAS NESTE CODIGO AS ENTRADAS DE MERCADORIAS EM ESTABELECIMENTO COMERCIAL DE COOPERATIVA RECEBIDAS DE SEUS COOPERADOS OU DE ESTABELECIMENTO DE OUTRA COOPERATIVA.','1'),
 (5,'1111','COMPRA PARA INDUSTRIALIZACAO DE MERCADORIA RECEBIDA ANTERIORMENTE EM CONSIGNACAO INDUSTRIAL','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS EFETIVAS DE MERCADORIAS A SEREM UTILIZADAS EM PROCESSO DE INDUSTRIALIZACAO, RECEBIDAS ANTERIORMENTE A TITULO DE CONSIGNACAO INDUSTRIAL.','1'),
 (6,'1113','COMPRA PARA COMERCIALIZACAO, DE MERCADORIA RECEBIDA ANTERIORMENTE EM CONSIGNACAO MERCANTIL','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS EFETIVAS DE MERCADORIAS RECEBIDAS ANTERIORMENTE A TITULO DE CONSIGNACAO MERCANTIL.','1'),
 (7,'1116','COMPRA PARA INDUSTRIALIZACAO OU PRODUCAO RURAL ORIGINADA DE ENCOMENDA PARA RECEBIMENTO FUTURO (NR AJUSTE SINIEF 05/2005) (DECRETO 28.868/2006)','COMPRA DE MERCADORIA, A SER UTILIZADA EM PROCESSO DE INDUSTRIALIZACAO OU PRODUCAO RURAL, QUANDO DA ENTRADA REAL DA MERCADORIA, CUJA AQUISICAO TENHA SIDO CLASSIFICADA NO CODIGO â1.922 â LANCAMENTO EFETUADO A TITULO DE SIMPLES FATURAMENTO DECORRENTE DE COMPRA PARA RECEBIMENTO FUTUROâ.\r\n\r\n (DECRETO NO 28.868, DE 31/01/2006-â EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005).','1'),
 (8,'1117','COMPRA PARA COMERCIALIZACAO ORIGINADA DE ENCOMENDA PARA RECEBIMENTO FUTURO','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS DE MERCADORIAS A SEREM COMERCIALIZADAS, QUANDO DA ENTRADA REAL DA MERCADORIA, CUJA AQUISICAO TENHA SIDO CLASSIFICADA NO CODIGO 1.922 - LANCAMENTO EFETUADO A TITULO DE SIMPLES FATURAMENTO DECORRENTE DE COMPRA PARA RECEBIMENTO FUTURO.','1'),
 (9,'1118','COMPRA DE MERCADORIA PARA COMERCIALIZACAO PELO ADQUIRENTE ORIGINARIO, ENTREGUE PELO VENDEDOR REMETENTE AO DESTINATARIO, EM VENDA A ORDEM.','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS DE MERCADORIAS JA COMERCIALIZADAS, QUE, SEM TRANSITAR PELO ESTABELECIMENTO DO ADQUIRENTE ORIGINARIO, SEJAM ENTREGUES PELO VENDEDOR REMETENTE DIRETAMENTE AO DESTINATARIO, EM OPERACAO DE VENDA A ORDEM, CUJA VENDA SEJA CLASSIFICADA, PELO ADQUIRENTE ORIGINARIO, NO CODIGO 5.120 - VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS ENTREGUE AO DESTINATARIO PELO VENDEDOR REMETENTE, EM VENDA A ORDEM.','1'),
 (10,'1120','COMPRA PARA INDUSTRIALIZACAO, EM VENDA A ORDEM, JA RECEBIDA DO VENDEDOR REMETENTE','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS DE MERCADORIAS A SEREM UTILIZADAS EM PROCESSO DE INDUSTRIALIZACAO, EM VENDAS A ORDEM, JA RECEBIDAS DO VENDEDOR REMETENTE, POR ORDEM DO ADQUIRENTE ORIGINARIO.','1'),
 (11,'1121','COMPRA PARA COMERCIALIZACAO, EM VENDA A ORDEM, JA RECEBIDA DO VENDEDOR REMETENTE','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS DE MERCADORIAS A SEREM COMERCIALIZADAS, EM VENDAS A ORDEM, JA RECEBIDAS DO VENDEDOR REMETENTE POR ORDEM DO ADQUIRENTE ORIGINARIO.','1'),
 (12,'1122','COMPRA PARA INDUSTRIALIZACAO EM QUE A MERCADORIA FOI REMETIDA PELO FORNECEDOR AO INDUSTRIALIZADOR SEM TRANSITAR PELO ESTABELECIMENTO ADQUIRENTE','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS DE MERCADORIAS A SEREM UTILIZADAS EM PROCESSO DE INDUSTRIALIZACAO, REMETIDAS PELO FORNECEDOR PARA O INDUSTRIALIZADOR SEM QUE A MERCADORIA TENHA TRANSITADO PELO ESTABELECIMENTO DO ADQUIRENTE.','1'),
 (13,'1124','INDUSTRIALIZACAO EFETUADA POR OUTRA EMPRESA','CLASSIFICAM-SE NESTE CODIGO AS ENTRADAS DE MERCADORIAS INDUSTRIALIZADAS POR TERCEIROS, COMPREENDENDO OS VALORES REFERENTES AOS SERVICOS PRESTADOS E OS DAS MERCADORIAS DE PROPRIEDADE DO INDUSTRIALIZADOR EMPREGADAS NO PROCESSO INDUSTRIAL. QUANDO A INDUSTRIALIZACAO EFETUADA SE REFERIR A BENS DO ATIVO IMOBILIZADO OU DE MERCADORIAS PARA USO OU CONSUMO DO ESTABELECIMENTO ENCOMENDANTE, A ENTRADA DEVERA SER CLASSIFICADA NOS CODIGOS 1.551 - COMPRA DE BEM PARA O ATIVO IMOBILIZADO OU 1.556 - COMPRA DE MATERIAL PARA USO OU CONSUMO.','1'),
