 (131,'2100','COMPRAS PARA INDUSTRIALIZACAO, PRODUCAO RURAL, COMERCIALIZACAO OU PRESTACAO DE SERVICOS (NR AJUSTE SINIEF 05/2005  (DECRETO 28.868/2006)','(NR AJUSTE SINIEF 05/2005) (DEC. 28.868/2006 - EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (132,'2101','COMPRA PARA INDUSTRIALIZACAO OU PRODUCAO RURAL (NR AJUSTE SINIEF 05/2005) (DECRETO 28.868/2006)','COMPRA DE MERCADORIA A SER UTILIZADA EM PROCESSO DE INDUSTRIALIZACAO OU PRODUCAO RURAL, BEM COMO A ENTRADA DE MERCADORIA EM ESTABELECIMENTO INDUSTRIAL OU PRODUTOR RURAL DE COOPERATIVA, RECEBIDA DE SEUS COOPERADOS OU DE ESTABELECIMENTO DE OUTRA COOPERATIVA.\r\n\r\n(NR AJUSTE SINIEF 05/2005) (DEC. 28.868/2006 - EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (133,'2102','COMPRA PARA COMERCIALIZACAO','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS DE MERCADORIAS A SEREM COMERCIALIZADAS. TAMBEM SERAO CLASSIFICADAS NESTE CODIGO AS ENTRADAS DE MERCADORIAS EM ESTABELECIMENTO COMERCIAL DE COOPERATIVA RECEBIDAS DE SEUS COOPERADOS OU DE ESTABELECIMENTO DE OUTRA COOPERATIVA.','1'),
