 (136,'2116','COMPRA PARA INDUSTRIALIZACAO OU PRODUCAO RURAL ORIGINADA DE ENCOMENDA PARA RECEBIMENTO FUTURO (NR AJUSTE SINIEF 05/2005) (DECRETO 28.868/2006)','COMPRA DE MERCADORIA A SER UTILIZADA EM PROCESSO DE INDUSTRIALIZACAO OU PRODUCAO RURAL, QUANDO DA ENTRADA REAL DA MERCADORIA, CUJA AQUISICAO TENHA SIDO CLASSIFICADA NO CODIGO \"2.922 â LANCAMENTO EFETUADO A TITULO DE SIMPLES FATURAMENTO DECORRENTE DE COMPRA PARA RECEBIMENTO FUTURO\".\r\n\r\n(NR AJUSTE SINIEF 05/2005) (DEC. 28.868/2006 - EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (137,'2117','COMPRA PARA COMERCIALIZACAO ORIGINADA DE ENCOMENDA PARA RECEBIMENTO FUTURO','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS DE MERCADORIAS A SEREM COMERCIALIZADAS, QUANDO DA ENTRADA REAL DA MERCADORIA, CUJA AQUISICAO TENHA SIDO CLASSIFICADA NO CODIGO 2.922 - LANCAMENTO EFETUADO A TITULO DE SIMPLES FATURAMENTO DECORRENTE DE COMPRA PARA RECEBIMENTO FUTURO.','1'),
 (138,'2118','COMPRA DE MERCADORIA PARA COMERCIALIZACAO PELO ADQUIRENTE ORIGINARIO, ENTREGUE PELO VENDEDOR REMETENTE AO DESTINATARIO, EM VENDA A ORDEM','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS DE MERCADORIAS JA COMERCIALIZADAS, QUE, SEM TRANSITAR PELO ESTABELECIMENTO DO ADQUIRENTE ORIGINARIO, SEJAM ENTREGUES PELO VENDEDOR REMETENTE DIRETAMENTE AO DESTINATARIO, EM OPERACAO DE VENDA A ORDEM, CUJA VENDA SEJA CLASSIFICADA, PELO ADQUIRENTE ORIGINARIO, NO CODIGO 6.120 - VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS ENTREGUE AO DESTINATARIO PELO VENDEDOR REMETENTE, EM VENDA A ORDEM.','1'),
 (139,'2120','COMPRA PARA INDUSTRIALIZACAO, EM VENDA A ORDEM, JA RECEBIDA DO VENDEDOR REMETENTE','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS DE MERCADORIAS A SEREM UTILIZADAS EM PROCESSO DE INDUSTRIALIZACAO, EM VENDAS A ORDEM, JA RECEBIDAS DO VENDEDOR REMETENTE, POR ORDEM DO ADQUIRENTE ORIGINARIO.','1'),
 (140,'2121','COMPRA PARA COMERCIALIZACAO, EM VENDA A ORDEM, JA RECEBIDA DO VENDEDOR REMETENTE','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS DE MERCADORIAS A SEREM COMERCIALIZADAS, EM VENDAS A ORDEM, JA RECEBIDAS DO VENDEDOR REMETENTE POR ORDEM DO ADQUIRENTE ORIGINARIO.','1'),
 (141,'2122','COMPRA PARA INDUSTRIALIZACAO EM QUE A MERCADORIA FOI REMETIDA PELO FORNECEDOR AO INDUSTRIALIZADOR SEM TRANSITAR PELO ESTABELECIMENTO ADQUIRENTE','CLASSIFICAM-SE NESTE CODIGO AS COMPRAS DE MERCADORIAS A SEREM UTILIZADAS EM PROCESSO DE INDUSTRIALIZACAO, REMETIDAS PELO FORNECEDOR PARA O INDUSTRIALIZADOR SEM QUE A MERCADORIA TENHA TRANSITADO PELO ESTABELECIMENTO DO ADQUIRENTE.','1'),
 (142,'2124','INDUSTRIALIZACAO EFETUADA POR OUTRA EMPRESA','CLASSIFICAM-SE NESTE CODIGO AS ENTRADAS DE MERCADORIAS INDUSTRIALIZADAS POR TERCEIROS, COMPREENDENDO OS VALORES REFERENTES AOS SERVICOS PRESTADOS E OS DAS MERCADORIAS DE PROPRIEDADE DO INDUSTRIALIZADOR EMPREGADAS NO PROCESSO INDUSTRIAL. QUANDO A INDUSTRIALIZACAO EFETUADA SE REFERIR A BENS DO ATIVO IMOBILIZADO OU DE MERCADORIAS PARA USO OU CONSUMO DO ESTABELECIMENTO ENCOMENDANTE, A ENTRADA DEVERA SER CLASSIFICADA NOS CODIGOS 2.551 - COMPRA DE BEM PARA O ATIVO IMOBILIZADO OU 2.556 - COMPRA DE MATERIAL PARA USO OU CONSUMO.','1'),
 (143,'2125','INDUSTRIALIZACAO EFETUADA POR OUTRA EMPRESA QUANDO A MERCADORIA REMETIDA PARA UTILIZACAO NO PROCESSO DE INDUSTRIALIZACAO NAO TRANSITOU PELO ESTABELECIMENTO ADQUIRENTE DA MERCADORIA','CLASSIFICAM-SE NESTE CODIGO AS ENTRADAS DE MERCADORIAS INDUSTRIALIZADAS POR OUTRAS EMPRESAS, EM QUE AS MERCADORIAS REMETIDAS PARA UTILIZACAO NO PROCESSO DE INDUSTRIALIZACAO NAO TRANSITARAM PELO ESTABELECIMENTO DO ADQUIRENTE DAS MERCADORIAS, COMPREENDENDO OS VALORES REFERENTES AOS SERVICOS PRESTADOS E OS DAS MERCADORIAS DE PROPRIEDADE DO INDUSTRIALIZADOR EMPREGADAS NO PROCESSO INDUSTRIAL. QUANDO A INDUSTRIALIZACAO EFETUADA SE REFERIR A BENS DO ATIVO IMOBILIZADO OU DE MERCADORIAS PARA USO OU CONSUMO DO ESTABELECIMENTO ENCOMENDANTE, A ENTRADA DEVERA SER CLASSIFICADA NOS CODIGOS 2.551 - COMPRA DE BEM PARA O ATIVO IMOBILIZADO OU 2.556 - COMPRA DE MATERIAL PARA USO OU CONSUMO.','1'),
