 (304,'5120','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS ENTREGUE AO DESTINATARIO PELO VENDEDOR REMETENTE, EM VENDA A ORDEM','CLASSIFICAM-SE NESTE CODIGO AS VENDAS A ORDEM DE MERCADORIAS ADQUIRIDAS OU RECEBIDAS DE TERCEIROS, QUE NAO TENHAM SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO, ENTREGUES PELO VENDEDOR REMETENTE AO DESTINATARIO, CUJA COMPRA SEJA CLASSIFICADA, PELO ADQUIRENTE ORIGINARIO, NO CODIGO 1.118 - COMPRA DE MERCADORIA PELO ADQUIRENTE ORIGINARIO, ENTREGUE PELO VENDEDOR REMETENTE AO DESTINATARIO, EM VENDA A ORDEM.','1'),
 (305,'5122','VENDA DE PRODUCAO DO ESTABELECIMENTO REMETIDA PARA INDUSTRIALIZACAO, POR CONTA E ORDEM DO ADQUIRENTE, SEM TRANSITAR PELO ESTABELECIMENTO DO ADQUIRENTE','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE PRODUTOS INDUSTRIALIZADOS NO ESTABELECIMENTO, REMETIDOS PARA SEREM INDUSTRIALIZADOS EM OUTRO ESTABELECIMENTO, POR CONTA E ORDEM DO ADQUIRENTE, SEM QUE OS PRODUTOS TENHAM TRANSITADO PELO ESTABELECIMENTO DO ADQUIRENTE.','1'),
