 (421,'5917','REMESSA DE MERCADORIA EM CONSIGNACAO MERCANTIL OU INDUSTRIAL','CLASSIFICAM-SE NESTE CODIGO AS REMESSAS DE MERCADORIAS A TITULO DE CONSIGNACAO MERCANTIL OU INDUSTRIAL.','1'),
 (422,'5918','DEVOLUCAO DE MERCADORIA RECEBIDA EM CONSIGNACAO MERCANTIL OU INDUSTRIAL','CLASSIFICAM-SE NESTE CODIGO AS DEVOLUCOES DE MERCADORIAS RECEBIDAS ANTERIORMENTE A TITULO DE CONSIGNACAO MERCANTIL OU INDUSTRIAL.','1'),
 (423,'5919','DEVOLUCAO SIMBOLICA DE MERCADORIA VENDIDA OU UTILIZADA EM PROCESSO INDUSTRIAL, RECEBIDA ANTERIORMENTE EM CONSIGNACAO MERCANTIL OU INDUSTRIAL','CLASSIFICAM-SE NESTE CODIGO AS DEVOLUCOES SIMBOLICAS DE MERCADORIAS VENDIDAS OU UTILIZADAS EM PROCESSO INDUSTRIAL, QUE TENHAM SIDO RECEBIDAS ANTERIORMENTE A TITULO DE CONSIGNACAO MERCANTIL OU INDUSTRIAL.','1'),
