 (427,'5923','REMESSA DE MERCADORIA POR CONTA E ORDEM DE TERCEIROS, EM VENDA A ORDEM','CLASSIFICAM-SE NESTE CODIGO AS SAIDAS CORRESPONDENTES A ENTREGA DE MERCADORIAS POR CONTA E ORDEM DE TERCEIROS, EM VENDAS A ORDEM, CUJA VENDA AO ADQUIRENTE ORIGINARIO, FOI CLASSIFICADA NOS CODIGOS 5.118 - VENDA DE PRODUCAO DO ESTABELECIMENTO ENTREGUE AO DESTINATARIO POR CONTA E ORDEM DO ADQUIRENTE ORIGINARIO, EM VENDA A ORDEM OU 5.119','1'),
 (428,'5924','REMESSA PARA INDUSTRIALIZACAO POR CONTA E ORDEM DO ADQUIRENTE DA MERCADORIA, QUANDO ESTA NAO TRANSITAR PELO ESTABELECIMENTO DO ADQUIRENTE','CLASSIFICAM-SE NESTE CODIGO AS SAIDAS DE INSUMOS COM DESTINO A ESTABELECIMENTO INDUSTRIALIZADOR, PARA SEREM INDUSTRIALIZADOS POR CONTA E ORDEM DO ADQUIRENTE, NAS HIPOTESES EM QUE OS INSUMOS NAO TENHAM TRANSITADO PELO ESTABELECIMENTO DO ADQUIRENTE DOS MESMOS.','1'),
 (429,'5925','RETORNO DE MERCADORIA RECEBIDA PARA INDUSTRIALIZACAO POR CONTA E ORDEM DO ADQUIRENTE DA MERCADORIA, QUANDO AQUELA NAO TRANSITAR PELO ESTABELECIMENTO DO ADQUIRENTE','CLASSIFICAM-SE NESTE CODIGO AS REMESSAS, PELO ESTABELECIMENTO INDUSTRIALIZADOR, DOS INSUMOS RECEBIDOS, POR CONTA E ORDEM DO ADQUIRENTE, PARA INDUSTRIALIZACAO E INCORPORADOS AO PRODUTO FINAL, NAS HIPOTESES EM QUE OS INSUMOS NAO TENHAM TRANSITADO PELO ESTABELECIMENTO DO ADQUIRENTE. O VALOR DOS INSUMOS NESTA OPERACAO DEVERA SER IGUAL AO VALOR DOS INSUMOS RECEBIDOS PARA INDUSTRIALIZACAO.','1'),
 (430,'5926','LANCAMENTO EFETUADO A TITULO DE RECLASSIFICACAO DE MERCADORIA DECORRENTE DE FORMACAO DE KIT OU DE SUA DESAGREGACAO','CLASSIFICAM-SE NESTE CODIGO OS REGISTROS EFETUADOS A TITULO DE RECLASSIFICACAO DECORRENTE DE FORMACAO DE KIT DE MERCADORIAS OU DE SUA DESAGREGACAO.','1'),
 (431,'5927','LANCAMENTO EFETUADO A TITULO DE BAIXA DE ESTOQUE DECORRENTE DE PERDA, ROUBO OU DETERIORACAO','CLASSIFICAM-SE NESTE CODIGO OS REGISTROS EFETUADOS A TITULO DE BAIXA DE ESTOQUE DECORRENTE DE PERDA, ROUBOU OU DETERIORACAO DAS MERCADORIAS.','1'),
 (432,'5928','LANCAMENTO EFETUADO A TITULO DE BAIXA DE ESTOQUE DECORRENTE DE PERDA, ROUBO OU DETERIORACAO','CLASSIFICAM-SE NESTE CODIGO OS REGISTROS EFETUADOS A TITULO DE BAIXA DE ESTOQUE DECORRENTE DE PERDA, ROUBOU OU DETERIORACAO DAS MERCADORIAS.','1'),
 (433,'5929','LANC. EFET. EM DECORRENCIA DE EMI. DE DOC. EMISSOR ECF','CLASSIFICAM-SE NESTE CODIGO OS REGISTROS RELATIVOS AOS DOCUMENTOS FISCAIS EMITIDOS EM OPERACOES OU PRESTACOES QUE TAMBEM TENHAM SIDO REGISTRADAS EM EQUIPAMENTO EMISSOR DE CUPOM FISCAL - ECF.','1'),
 (434,'5931','LANCAMENTO EFETUADO EM DECORRENCIA DA RESPONSABILIDADE DE RETENCAO DO IMPOSTO POR SUBSTITUICAO TRIBUTARIA, ATRIBUIDA AO REMETENTE OU ALIENANTE DA MERCADORIA, PELO SERVICO DE TRANSPORTE REALIZADO POR TRANSPORTADOR AUTONOMO OU POR TRANSPORTADOR NAO INSCRITO NA UNIDADE DA FEDERACAO ONDE INICIADO O SERVICO','CLASSIFICAM-SE NESTE CODIGO EXCLUSIVAMENTE OS LANCAMENTOS EFETUADOS PELO REMETENTE OU ALIENANTE DA MERCADORIA QUANDO LHE FOR ATRIBUIDA A RESPONSABILIDADE PELO RECOLHIMENTO DO IMPOSTO DEVIDO PELO SERVICO DE TRANSPORTE REALIZADO POR TRANSPORTADOR AUTONOMO OU POR TRANSPORTADOR NAO INSCRITO NA UNIDADE DA FEDERACAO ONDE INICIADO O SERVICO.','1'),
 (435,'5932','PRESTACAO DE SERVICO DE TRANSPORTE INICIADA EM UNIDADE DA FEDERACAO DIVERSA DAQUELA ONDE INSCRITO O PRESTADOR','CLASSIFICAM-SE NESTE CODIGO AS PRESTACOES DE SERVICO DE TRANSPORTE QUE TENHAM SIDO INICIADAS EM UNIDADE DA FEDERACAO DIVERSA DAQUELA ONDE O PRESTADOR ESTA INSCRITO COMO CONTRIBUINTE.','1'),
 (436,'5933','PRESTACAO DE SERVICO TRIBUTADO PELO IMPOSTO SOBRE SERVICOS DE QUALQUER NATUREZA','PRESTACAO DE SERVICO, CUJO IMPOSTO E DE COMPETENCIA MUNICIPAL, DESDE QUE INFORMADO EM NOTA FISCAL MODELO 1 OU 1-A. (NR AJUSTE SINIEF 06/2005)A PARTIR DE 01/01/2006','1'),
 (437,'5949','OUTRA SAIDA DE MERCADORIA OU PRESTACAO DE SERVICO NAO ESPECIFICADO','CLASSIFICAM-SE NESTE CODIGO AS OUTRAS SAIDAS DE MERCADORIAS OU PRESTACOES DE SERVICOS QUE NAO TENHAM SIDO ESPECIFICADOS NOS CODIGOS ANTERIORES.','1'),
 (438,'6000','SAIDAS OU PRESTACOES DE SERVICOS PARA OUTROS ESTADOS','CLASSIFICAM-SE, NESTE GRUPO, AS OPERACOES OU PRESTACOES EM QUE O ESTABELECIMENTO REMETENTE ESTEJA LOCALIZADO EM UNIDADE DA FEDERACAO DIVERSA DAQUELA DO DESTINATARIO','1'),
 (439,'6101','VENDA DE PRODUCAO DO ESTABELECIMENTO','VENDA DE PRODUTO INDUSTRIALIZADO OU PRODUZIDO PELO ESTABELECIMENTO, BEM COMO A DE MERCADORIA POR ESTABELECIMENTO INDUSTRIAL OU PRODUTOR RURAL DE COOPERATIVA DESTINADA A SEUS COOPERADOS OU A ESTABELECIMENTO DE OUTRA COOPERATIVA.\r\n\r\n(NR AJUSTE SINIEF 05/2005) (DEC.28.868/2006 - EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (440,'6102','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE MERCADORIAS ADQUIRIDAS OU RECEBIDAS DE TERCEIROS PARA INDUSTRIALIZACAO OU COMERCIALIZACAO, QUE NAO TENHAM SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO. TAMBEM SERAO CLASSIFICADAS NESTE CODIGO AS VENDAS DE MERCADORIAS POR ESTABELECIMENTO COMERCIAL DE COOPERATIVA DESTINADAS A SEUS COOPERADOS OU ESTABELECIMENTO DE OUTRA COOPERATIVA.','1'),
 (441,'6103','VENDA DE PRODUCAO DO ESTABELECIMENTO, EFETUADA FORA DO ESTABELECIMENTO','VENDA EFETUADA FORA DO ESTABELECIMENTO, INCLUSIVE POR MEIO DE VEICULO, DE PRODUTO INDUSTRIALIZADO NO ESTABELECIMENTO.\r\n\r\n(NR AJUSTE SINIEF 05/2005) (DEC.28.868/2006 - EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (442,'6104','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS, EFETUADA FORA DO ESTABELECIMENTO','VENDA EFETUADA FORA DO ESTABELECIMENTO, INCLUSIVE POR MEIO DE VEICULO, DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIRO PARA INDUSTRIALIZACAO OU COMERCIALIZACAO, QUE NAO TENHA SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO.','1'),
 (443,'6105','VENDA DE PRODUCAO DO ESTABELECIMENTO QUE NAO DEVA POR ELE TRANSITAR','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE PRODUTOS INDUSTRIALIZADOS NO ESTABELECIMENTO, ARMAZENADOS EM DEPOSITO FECHADO, ARMAZEM GERAL OU OUTRO SEM QUE HAJA RETORNO AO ESTABELECIMENTO DEPOSITANTE.','1'),
 (444,'6106','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS, QUE NAO DEVA POR ELE TRANSITAR','VENDAS DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIRO PARA INDUSTRIALIZACAO OU COMERCIALIZACAO, ARMAZENADA EM DEPOSITO FECHADO, ARMAZEM GERAL OU OUTRO, QUE NAO TENHA SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO SEM QUE HAJA RETORNO AO ESTABELECIMENTO DEPOSITANTE. BEM COMO VENDA DE MERCADORIA IMPORTADA, CUJA SAIDA OCORRA DO RECINTO ALFANDEGADO OU DA REPARTICAO ALFANDEGARIA ONDE SE PROCESSOU O DESEMBARACO ADUANEIRO, COM DESTINO AO ESTABELECIMENTO DO COMPRADOR, SEM QUE TENHA TRANSITADO PELO ESTABELECIMENTO DO IMPORTADOR.','1'),
 (445,'6107','VENDA DE PRODUCAO DO ESTABELECIMENTO, DESTINADA A NAO CONTRIBUINTE','VENDAS DE PRODUTO INDUSTRIALIZADO NO ESTABELECIMENTO, OU PRODUZIDO NO ESTABELECIMENTO DO PRODUTOR RURAL, DESTINADA A NAO CONTRIBUINTE, BEM COMO QUALQUER OPERACAO DE VENDA DESTINADA A NAO CONTRIBUINTE\r\n\r\n (NR AJUSTE SINIEF 05/2005) (DEC.28.868/2006 - EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (446,'6108','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS, DESTINADA A NAO CONTRIBUINTE','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE MERCADORIAS ADQUIRIDAS OU RECEBIDAS DE TERCEIROS PARA INDUSTRIALIZACAO OU COMERCIALIZACAO, QUE NAO TENHAM SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO, DESTINADAS A NAO CONTRIBUINTES. QUAISQUER OPERACOES DE VENDA DESTINADAS A NAO CONTRIBUINTES DEVERAO SER CLASSIFICADAS NESTE CODIGO.','1'),
 (447,'6109','VENDA DE PRODUCAO DO ESTABELECIMENTO DESTINADA A ZONA FRANCA DE MANAUS OU AREAS DE LIVRE COMERCIO','VENDA DE PRODUTO INDUSTRIALIZADO OU PRODUZIDO PELO ESTABELECIMENTO DESTINADO A ZONA FRANCA DE MANAUS OU AREAS DE LIVRE COMERCIO.\r\n\r\n(NR AJUSTE SINIEF 05/2005) (DEC.28.868/2006 - EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (448,'6110','VENDA DE MERCADORIA, ADQUIRIDA OU RECEBIDA DE TERCEIROS, DESTINADA A ZONA FRANCA DE MANAUS OU AREAS DE LIVRE COMERCIO, DE QUE TRATA O ANEXO DO CONVENIO SINIEF S/N, DE 15 DE DEZEMBRO DE 1970, QUE DISPOE SOBRE O SISTEMA NACIONAL INTEGRADO DE INFORMACOES ECONOMICO-FISCAIS (DECRETO NO 26.955/2004) RETROAGINDO SEUS EFEITOS A 24.06.2004','VENDA DE MERCADORIA, ADQUIRIDA OU RECEBIDA DE TERCEIROS, DESTINADA A ZONA FRANCA DE MANAUS OU AREAS DE LIVRE COMERCIO, DESDE QUE ALCANCADA PELOS BENEFICIOS FISCAIS DE QUE TRATAM O DECRETO-LEI NO 288, DE 28 DE FEVEREIRO DE 1967, O CONVENIO ICM 65/88, DE 06 DE DEZEMBRO DE 1988, O CONVENIO ICMS 36/97, DE 23 DE MAIO DE 1997, E O CONVENIO ICMS 37/97, DE 23 DE MAIO DE 1997. (NR AJUSTE SINIEF 09/2004) (DECRETO NO 26.955/2004) RETROAGINDO SEUS EFEITOS A 24.06.2004','1'),
 (449,'6111','VENDA DE PRODUCAO DO ESTABELECIMENTO REMETIDA ANTERIORMENTE EM CONSIGNACAO INDUSTRIAL','CLASSIFICAM-SE NESTE CODIGO AS VENDAS EFETIVAS DE PRODUTOS INDUSTRIALIZADOS NO ESTABELECIMENTO REMETIDOS ANTERIORMENTE A TITULO DE CONSIGNACAO INDUSTRIAL.','1'),
 (450,'6112','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS REMETIDA ANTERIORMENTE EM CONSIGNACAO INDUSTRIAL','CLASSIFICAM-SE NESTE CODIGO AS VENDAS EFETIVAS DE MERCADORIAS ADQUIRIDAS OU RECEBIDAS DE TERCEIROS, QUE NAO TENHAM SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO, REMETIDAS ANTERIORMENTE A TITULO DE CONSIGNACAO INDUSTRIAL.','1'),
 (451,'6113','VENDA DE PRODUCAO DO ESTABELECIMENTO REMETIDA ANTERIORMENTE EM CONSIGNACAO MERCANTIL','CLASSIFICAM-SE NESTE CODIGO AS VENDAS EFETIVAS DE PRODUTOS INDUSTRIALIZADOS NO ESTABELECIMENTO REMETIDOS ANTERIORMENTE A TITULO DE CONSIGNACAO MERCANTIL.','1'),
 (452,'6114','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS REMETIDA ANTERIORMENTE EM CONSIGNACAO MERCANTIL','CLASSIFICAM-SE NESTE CODIGO AS VENDAS EFETIVAS DE MERCADORIAS ADQUIRIDAS OU RECEBIDAS DE TERCEIROS, QUE NAO TENHAM SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO, REMETIDAS ANTERIORMENTE A TITULO DE CONSIGNACAO MERCANTIL.','1'),
 (453,'6115','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS, RECEBIDA ANTERIORMENTE EM CONSIGNACAO MERCANTIL','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE MERCADORIAS ADQUIRIDAS OU RECEBIDAS DE TERCEIROS, RECEBIDAS ANTERIORMENTE A TITULO DE CONSIGNACAO MERCANTIL.','1'),
 (454,'6116','VENDA DE PRODUCAO DO ESTABELECIMENTO ORIGINADA DE ENCOMENDA PARA ENTREGA FUTURA','VENDA DE PRODUTO INDUSTRIALIZADO OU PRODUZIDO PELO ESTABELECIMENTO, QUANDO DA SAIDA REAL DO PRODUTO, CUJO FATURAMENTO TENHA SIDO CLASSIFICADO NO CODIGO \"5.922 â LANCAMENTO EFETUADO A TITULO DE SIMPLES FATURAMENTO DECORRENTE DE VENDA PARA ENTREGA FUTURA\".\r\n\r\n(NR AJUSTE SINIEF 05/2005) (DEC.28.868/2006 - EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (455,'6117','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS, ORIGINADA DE ENCOMENDA PARA ENTREGA FUTURA','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE MERCADORIAS ADQUIRIDAS OU RECEBIDAS DE TERCEIROS, QUE NAO TENHAM SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO, QUANDO DA SAIDA REAL DA MERCADORIA, CUJO FATURAMENTO TENHA SIDO CLASSIFICADO NO CODIGO 6.922 - LANCAMENTO EFETUADO A TITULO DE SIMPLES FATURAMENTO DECORRENTE DE VENDA PARA ENTREGA FUTURA.','1'),
 (456,'6118','VENDA DE PRODUCAO DO ESTABELECIMENTO ENTREGUE AO DESTINATARIO POR CONTA E ORDEM DO ADQUIRENTE ORIGINARIO, EM VENDA A ORDEM','CLASSIFICAM-SE NESTE CODIGO AS VENDAS A ORDEM DE PRODUTOS INDUSTRIALIZADOS PELO ESTABELECIMENTO, ENTREGUES AO DESTINATARIO POR CONTA E ORDEM DO ADQUIRENTE ORIGINARIO.','1'),
 (457,'6119','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS ENTREGUE AO DESTINATARIO POR CONTA E ORDEM DO ADQUIRENTE ORIGINARIO, EM VENDA A ORDEM','CLASSIFICAM-SE NESTE CODIGO AS VENDAS A ORDEM DE MERCADORIAS ADQUIRIDAS OU RECEBIDAS DE TERCEIROS, QUE NAO TENHAM SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO, ENTREGUES AO DESTINATARIO POR CONTA E ORDEM DO ADQUIRENTE ORIGINARIO.','1'),
 (458,'6120','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS ENTREGUE AO DESTINATARIO PELO VENDEDOR REMETENTE, EM VENDA A ORDEM','CLASSIFICAM-SE NESTE CODIGO AS VENDAS A ORDEM DE MERCADORIAS ADQUIRIDAS OU RECEBIDAS DE TERCEIROS, QUE NAO TENHAM SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO, ENTREGUES PELO VENDEDOR REMETENTE AO DESTINATARIO, CUJA COMPRA SEJA CLASSIFICADA, PELO ADQUIRENTE ORIGINARIO, NO CODIGO 2.118 - COMPRA DE MERCADORIA PELO ADQUIRENTE ORIGINARIO, ENTREGUE PELO VENDEDOR REMETENTE AO DESTINATARIO, EM VENDA A ORDEM.','1'),
 (459,'6122','VENDA DE PRODUCAO DO ESTABELECIMENTO REMETIDA PARA INDUSTRIALIZACAO, POR CONTA E ORDEM DO ADQUIRENTE, SEM TRANSITAR PELO ESTABELECIMENTO DO ADQUIRENTE','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE PRODUTOS INDUSTRIALIZADOS NO ESTABELECIMENTO, REMETIDOS PARA SEREM INDUSTRIALIZADOS EM OUTRO ESTABELECIMENTO, POR CONTA E ORDEM DO ADQUIRENTE, SEM QUE OS PRODUTOS TENHAM TRANSITADO PELO ESTABELECIMENTO DO ADQUIRENTE.','1'),
 (460,'6123','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS REMETIDA PARA INDUSTRIALIZACAO, POR CONTA E ORDEM DO ADQUIRENTE, SEM TRANSITAR PELO ESTABELECIMENTO DO ADQUIRENTE','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE MERCADORIAS ADQUIRIDAS OU RECEBIDAS DE TERCEIROS, QUE NAO TENHAM SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO, REMETIDAS PARA SEREM INDUSTRIALIZADAS EM OUTRO ESTABELECIMENTO, POR CONTA E ORDEM DO ADQUIRENTE, SEM QUE AS MERCADORIAS TENHAM TRANSITADO PELO ESTABELECIMENTO DO ADQUIRENTE.','1'),
 (461,'6124','INDUSTRIALIZACAO EFETUADA PARA OUTRA EMPRESA','CLASSIFICAM-SE NESTE CODIGO AS SAIDAS DE MERCADORIAS INDUSTRIALIZADAS PARA TERCEIROS, COMPREENDENDO OS VALORES REFERENTES AOS SERVICOS PRESTADOS E OS DAS MERCADORIAS DE PROPRIEDADE DO INDUSTRIALIZADOR EMPREGADAS NO PROCESSO INDUSTRIAL.','1'),
 (462,'6125','INDUSTRIALIZACAO EFETUADA PARA OUTRA EMPRESA QUANDO A MERCADORIA RECEBIDA PARA UTILIZACAO NO PROCESSO DE INDUSTRIALIZACAO NAO TRANSITAR PELO ESTABELECIMENTO ADQUIRENTE DA MERCADORIA','CLASSIFICAM-SE NESTE CODIGO AS SAIDAS DE MERCADORIAS INDUSTRIALIZADAS PARA OUTRAS EMPRESAS, EM QUE AS MERCADORIAS RECEBIDAS PARA UTILIZACAO NO PROCESSO DE INDUSTRIALIZACAO NAO TENHAM TRANSITADO PELO ESTABELECIMENTO DO ADQUIRENTE DAS MERCADORIAS, COMPREENDENDO OS VALORES REFERENTES AOS SERVICOS PRESTADOS E OS DAS MERCADORIAS DE PROPRIEDADE DO INDUSTRIALIZADOR EMPREGADAS NO PROCESSO INDUSTRIAL.','1'),
 (463,'6150','TRANSFERENCIAS DE PRODUCAO PROPRIA OU DE TERCEIROS','','1'),
 (464,'6151','TRANSFERENCIA DE PRODUCAO DO ESTABELECIMENTO','PRODUTOS INDUSTRIALIZADO OU PRODUZIDO NO ESTABELECIMENTO E TRANSFERIDO PARA OUTRO ESTABELECIMENTO DA MESMA EMPRESA.\r\n\r\n(NR AJUSTE SINIEF 05/2005) (DEC.28.868/2006 - EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (465,'6152','TRANSFERENCIA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS','MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS PARA INDUSTRIALIZACAO, COMERCIALIZACAO OU UTILIZACAO NA PRESTACAO DE SERVICO E QUE NAO TENHA SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO, TRANSFERIDA PARA OUTRO ESTABELECIMENTO DA MESMA EMPRESA. A PARTIR  10 DE JULHO DE 2003. (DECRETO NO 26.020/2003)','1'),
 (466,'6153','TRANSFERENCIA DE ENERGIA ELETRICA','CLASSIFICAM-SE NESTE CODIGO AS TRANSFERENCIAS DE ENERGIA ELETRICA PARA OUTRO ESTABELECIMENTO DA MESMA EMPRESA, PARA DISTRIBUICAO.','1'),
