 (584,'7100','VENDAS DE PRODUCAO PROPRIA OU DE TERCEIROS','','1'),
 (585,'7101','VENDA DE PRODUCAO DO ESTABELECIMENTO','VENDA DE PRODUTO INDUSTRIALIZADO OU PRODUZIDO PELO ESTABELECIMENTO, BEM COMO A DE MERCADORIA POR ESTABELECIMENTO INDUSTRIAL OU PRODUTOR RURAL DE COOPERATIVA DESTINADA A SEUS COOPERADOS OU A ESTABELECIMENTO DE OUTRA COOPERATIVA.\r\n\r\n(NR AJUSTE SINIEF 05/2005) (DEC.28.868/2006 - EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (586,'7102','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE MERCADORIAS ADQUIRIDAS OU RECEBIDAS DE TERCEIROS PARA INDUSTRIALIZACAO OU COMERCIALIZACAO, QUE NAO TENHAM SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO. TAMBEM SERAO CLASSIFICADAS NESTE CODIGO AS VENDAS DE MERCADORIAS POR ESTABELECIMENTO COMERCIAL DE COOPERATIVA.','1'),
 (587,'7105','VENDA DE PRODUCAO DO ESTABELECIMENTO, QUE NAO DEVA POR ELE TRANSITAR','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE PRODUTOS INDUSTRIALIZADOS NO ESTABELECIMENTO, ARMAZENADOS EM DEPOSITO FECHADO, ARMAZEM GERAL OU OUTRO SEM QUE HAJA RETORNO AO ESTABELECIMENTO DEPOSITANTE.','1'),
 (588,'7106','VENDA DE MERCADORIA ADQUIRIDA OU RECEBIDA DE TERCEIROS, QUE NAO DEVA POR ELE TRANSITAR','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE MERCADORIAS ADQUIRIDAS OU RECEBIDAS DE TERCEIROS PARA INDUSTRIALIZACAO OU COMERCIALIZACAO, ARMAZENADAS EM DEPOSITO FECHADO, ARMAZEM GERAL OU OUTRO, QUE NAO TENHAM SIDO OBJETO DE QUALQUER PROCESSO INDUSTRIAL NO ESTABELECIMENTO SEM QUE HAJA RETORNO AO ESTABELECIMENTO DEPOSITANTE. TAMBEM SERAO CLASSIFICADAS NESTE CODIGO AS VENDAS DE MERCADORIAS IMPORTADAS, CUJA SAIDA OCORRA DO RECINTO ALFANDEGADO OU DA REPARTICAO ALFANDEGARIA ONDE SE PROCESSOU O DESEMBARACO ADUANEIRO, COM DESTINO AO ESTABELECIMENTO DO COMPRADOR, SEM TRANSITAR PELO ESTABELECIMENTO DO IMPORTADOR.','1'),
 (589,'7127','VENDA DE PRODUCAO DO ESTABELECIMENTO SOB O REGIME DE DRAWBACK','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE PRODUTOS INDUSTRIALIZADOS NO ESTABELECIMENTO SOB O REGIME DE DRAWBACK , CUJAS COMPRAS FORAM CLASSIFICADAS NO CODIGO 3.127 - COMPRA PARA INDUSTRIALIZACAO SOB O REGIME DE DRAWBACK.','1'),
 (590,'7200','DEVOLUCOES DE COMPRAS PARA INDUSTRIALIZACAO, COMERCIALIZACAO OU ANULACOES DE VALORES','(NR AJUSTE SINIEF 05/2005) (DEC.28.868/2006 - EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (591,'7201','DEVOLUCAO DE COMPRA PARA INDUSTRIALIZACAO OU PRODUCAO RURAL (NR AJUSTE SINIEF 05/2005) (DECRETO 28.868/2006)','DEVOLUCAO DE MERCADORIA ADQUIRIDA PARA SER UTILIZADA EM PROCESSO DE INDUSTRIALIZACAO OU PRODUCAO RURAL, CUJA ENTRADA TENHA SIDO CLASSIFICADA COMO \"1.101 - COMPRA PARA INDUSTRIALIZACAO OU PRODUCAO RURAL\".\r\n\r\n(NR AJUSTE SINIEF 05/2005) (DEC.28.868/2006 - EFEITOS A PARTIR DE 01/01/2006, FICANDO FACULTADA AO CONTRIBUINTE A SUA ADOCAO PARA FATOS GERADORES OCORRIDOS NO PERIODO DE 01 DE NOVEMBRO A 31 DE DEZEMBRO DE 2005)','1'),
 (592,'7202','DEVOLUCAO DE COMPRA PARA COMERCIALIZACAO','CLASSIFICAM-SE NESTE CODIGO AS DEVOLUCOES DE MERCADORIAS ADQUIRIDAS PARA SEREM COMERCIALIZADAS, CUJAS ENTRADAS TENHAM SIDO CLASSIFICADAS COMO COMPRA PARA COMERCIALIZACAO.','1'),
 (593,'7205','ANULACAO DE VALOR RELATIVO A AQUISICAO DE SERVICO DE COMUNICACAO','CLASSIFICAM-SE NESTE CODIGO AS ANULACOES CORRESPONDENTES A VALORES FATURADOS INDEVIDAMENTE, DECORRENTES DAS AQUISICOES DE SERVICOS DE COMUNICACAO.','1'),
 (594,'7206','ANULACAO DE VALOR RELATIVO A AQUISICAO DE SERVICO DE TRANSPORTE','CLASSIFICAM-SE NESTE CODIGO AS ANULACOES CORRESPONDENTES A VALORES FATURADOS INDEVIDAMENTE, DECORRENTES DAS AQUISICOES DE SERVICOS DE TRANSPORTE.','1'),
 (595,'7207','ANULACAO DE VALOR RELATIVO A COMPRA DE ENERGIA ELETRICA','CLASSIFICAM-SE NESTE CODIGO AS ANULACOES CORRESPONDENTES A VALORES FATURADOS INDEVIDAMENTE, DECORRENTES DA COMPRA DE ENERGIA ELETRICA.','1'),
 (596,'7210','DEVOLUCAO DE COMPRA PARA UTILIZACAO NA PRESTACAO DE SERVICO','CLASSIFICAM-SE NESTE CODIGO AS DEVOLUCOES DE MERCADORIAS ADQUIRIDAS PARA UTILIZACAO NA PRESTACAO DE SERVICOS, CUJAS ENTRADAS TENHAM SIDO CLASSIFICADAS NO CODIGO 3.126 - COMPRA PARA UTILIZACAO NA PRESTACAO DE SERVICO.','1'),
 (597,'7211','DEVOLUCAO DE COMPRAS PARA INDUSTRIALIZACAO SOB O REGIME DE DRAWBACK','CLASSIFICAM-SE NESTE CODIGO AS DEVOLUCOES DE MERCADORIAS ADQUIRIDAS PARA SEREM UTILIZADAS EM PROCESSO DE INDUSTRIALIZACAO SOB O REGIME DE DRAWBACK E NAO UTILIZADAS NO REFERIDO PROCESSO, CUJAS ENTRADAS TENHAM SIDO CLASSIFICADAS NO CODIGO 3.127 - COMPRA PARA INDUSTRIALIZACAO SOB O REGIME DE DRAWBACK.','1'),
 (598,'7250','VENDAS DE ENERGIA ELETRICA','','1'),
 (599,'7251','VENDA DE ENERGIA ELETRICA PARA O EXTERIOR','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE ENERGIA ELETRICA PARA O EXTERIOR.','1'),
 (600,'7300','PRESTACOES DE SERVICOS DE COMUNICACAO','','1'),
 (601,'7301','PRESTACAO DE SERVICO DE COMUNICACAO PARA EXECUCAO DE SERVICO DA MESMA NATUREZA','CLASSIFICAM-SE NESTE CODIGO AS PRESTACOES DE SERVICOS DE COMUNICACAO DESTINADOS AS PRESTACOES DE SERVICOS DA MESMA NATUREZA.','1'),
 (602,'7358','PRESTACAO DE SERVICO DE TRANSPORTE','CLASSIFICAM-SE NESTE CODIGO AS PRESTACOES DE SERVICOS DE TRANSPORTE DESTINADO A ESTABELECIMENTO NO EXTERIOR.','1'),
 (603,'7500','EXPORTACAO DE MERCADORIAS RECEBIDAS COM FIM ESPECIFICO DE EXPORTACAO','','1'),
 (604,'7501','EXPORTACAO DE MERCADORIAS RECEBIDAS COM FIM ESPECIFICO DE EXPORTACAO','CLASSIFICAM-SE NESTE CODIGO AS EXPORTACOES DAS MERCADORIAS RECEBIDAS ANTERIORMENTE COM FINALIDADE ESPECIFICA DE EXPORTACAO, CUJAS ENTRADAS TENHAM SIDO CLASSIFICADAS NOS CODIGOS 1.501 - ENTRADA DE MERCADORIA RECEBIDA COM FIM ESPECIFICO DE EXPORTACAO OU 2.501 - ENTRADA DE MERCADORIA RECEBIDA COM FIM ESPECIFICO DE EXPORTACAO.','1'),
 (605,'7550','OPERACOES COM BENS DE ATIVO IMOBILIZADO E MATERIAIS PARA USO OU CONSUMO','','1'),
 (606,'7551','VENDA DE BEM DO ATIVO IMOBILIZADO','CLASSIFICAM-SE NESTE CODIGO AS VENDAS DE BENS INTEGRANTES DO ATIVO IMOBILIZADO DO ESTABELECIMENTO.','1'),
 (607,'7553','DEVOLUCAO DE COMPRA DE BEM PARA O ATIVO IMOBILIZADO','CLASSIFICAM-SE NESTE CODIGO AS DEVOLUCOES DE BENS ADQUIRIDOS PARA INTEGRAR O ATIVO IMOBILIZADO DO ESTABELECIMENTO, CUJA ENTRADA FOI CLASSIFICADA NO CODIGO 3.551 - COMPRA DE BEM PARA O ATIVO IMOBILIZADO.','1'),
 (608,'7556','DEVOLUCAO DE COMPRA DE MATERIAL DE USO OU CONSUMO','CLASSIFICAM-SE NESTE CODIGO AS DEVOLUCOES DE MERCADORIAS DESTINADAS AO USO OU CONSUMO DO ESTABELECIMENTO, CUJA ENTRADA TENHA SIDO CLASSIFICADA NO CODIGO 3.556 - COMPRA DE MATERIAL PARA USO OU CONSUMO.','1'),
 (609,'7650','SAIDAS DE COMBUSTIVEIS, DERIVADOS OU NAO DE PETROLEO, E LUBRIFICANTES','(A PARTIR 01.01.2004 -  DECRETO NO 26.174 DE 26/11/2003)','1'),
 (610,'7651','VENDA DE COMBUSTIVEL OU LUBRIFICANTE DE PRODUCAO DO ESTABELECIMENTO','VENDA DE COMBUSTIVEL OU LUBRIFICANTE INDUSTRIALIZADOS NO ESTABELECIMENTO E DESTINADOS AO EXTERIOR. (A PARTIR 01.01.2004 -  DECRETO NO 26.174 DE 26/11/2003)','1'),
 (611,'7654','VENDA DE COMBUSTIVEL OU LUBRIFICANTE ADQUIRIDOS OU RECEBIDOS DE TERCEIROS','VENDA DE COMBUSTIVEL OU LUBRIFICANTE, ADQUIRIDOS OU RECEBIDOS DE TERCEIROS, DESTINADOS AO EXTERIOR. (A PARTIR 01.01.2004 -  DECRETO NO 26.174 DE 26/11/2003)','1'),
 (612,'7667','VENDA DE COMBUSTIVEL OU LUBRIFICANTE A CONSUMIDOR OU USUARIO FINAL','VENDA DE COMBUSTIVEL OU LUBRIFICANTE A CONSUMIDOR OU A USUARIO FINAL, CUJA OPERACAO TENHA SIDO EQUIPARADA A UMA EXPORTACAO. ACR AJUSTE SINIEF 05/2009 â A PARTIR DE 01.07.2009)(DECRETO NO 34.490/2009)','1'),
 (613,'7900','OUTRAS SAIDAS DE MERCADORIA OU PRESTACOES DE SERVICOS','','1'),
 (614,'7930','LANCAMENTO EFETUADO A TITULO DE DEVOLUCAO DE BEM CUJA ENTRADA TENHA OCORRIDO SOB AMPARO DE REGIME ESPECIAL ADUANEIRO DE ADMISSAO TEMPORARIA','CLASSIFICAM-SE NESTE CODIGO OS LANCAMENTOS EFETUADOS A TITULO DE SAIDA EM DEVOLUCAO DE BENS CUJA ENTRADA TENHA OCORRIDO SOB AMPARO DE REGIME ESPECIAL ADUANEIRO DE ADMISSAO TEMPORARIA.','1'),
 (615,'7949','OUTRA SAIDA DE MERCADORIA OU PRESTACAO DE SERVICO NAO ESPECIFICADO','CLASSIFICAM-SE NESTE CODIGO AS OUTRAS SAIDAS DE MERCADORIAS OU PRESTACOES DE SERVICOS QUE NAO TENHAM SIDO ESPECIFICADOS NOS CODIGOS ANTERIORES.','1');
